var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"이 상태로 가뜩이나 미어터지는 집무실에서 만나자고 하신 겁니까. 진공관 맙소사.","JPN":"ただでさえ人間で溢れる社長室をわざと待ち合わせ場所にしたのですか？ オーマイ、真空管。","ENG":"Did you see me? What made you think meeting in your office would be a good idea? Oh my diodes.","TWN":"我的真空管，偏偏要在這種情況下，找我來這間擁擠的辦公室嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"최근 저는, 당신의 여러 비합리적인 의사 결정을 묵인해 왔습니다.","JPN":"この頃の私は、あなたの様々な非合理的な意思決定を黙認してきました。","ENG":"Recently, I have kept mum about your irrational decision making.","TWN":"對於你最近種種不合理的決定，我都沒有說話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"전투 형태에서는 기체 온도가 올라간다고 사무실 난방기 대신 사용할 방법을 찾는다거나, 수업에 지각한다고 열 쌍둥이의 스쿨 버스 대용으로 사용한다거나.","JPN":"戦闘形態では機体温度が上がるからといって事務室で暖房機の代わりに使う方法を探したり、授業に遅刻するからといって十つ子のスクールバスの代わりに使ったり。","ENG":"You looked for ways to have me replace the office heater since the combat mode generates so much heat, or even had me serve as a school bus for the decuplets when they were running late to class.","TWN":"像是說我在戰鬥狀態下體溫會升高，可以代替辦公室的暖氣，或是說上課快遲到，要我代替校車載十胞胎去學校。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"……하지만 결과적으로는 전부 수준 미달이었죠.","JPN":"……しかし結果的にはすべて水準に満たないものばかりで。","ENG":"But in the end, I have proven to be a mediocre alternative in every case.","TWN":"……但就結果而言都是白忙一場。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"당신의 기술 지원을 받더라도 이 프레임은 결국 본래 설계된 목적에서 벗어나지 못할 겁니다.","JPN":"あなたから技術的なサポートを受けても、このフレームは結局、本来の設計目的から抜け出せないでしょう。","ENG":"Even with your technical support, this frame will always be solely fit for its intended purpose.","TWN":"就算有你的技術支援，也無法跳脫這個軀殼原本設定的目的的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"선단 호위 및 적성체 요격. 즉, 병기라는 범주에서 말입니다.","JPN":"船団護衛および敵性体迎撃。つまり、兵器というカテゴリからです。","ENG":"Which is to escort ships and intercept hostile vehicles. It is, in short, a weapon.","TWN":"就是保護船隻和攻擊敵人，也就是作為兵器的用途。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"하지만 명심하십시오. 저는 그 목적성을 거부하지 않습니다.","JPN":"しかしくれぐれも忘れないように。私はその目的性を拒否しません。","ENG":"But mark my words. I will not deny such purpose.","TWN":"但請記住，我不會拒絕這種邀約。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"협력자인 당신과 함께 싸우기 위해, 지금 이곳에 있는 것이니 말입니다.","JPN":"協力者であるあなたと戦うために、今ここにいるのですから。","ENG":"For I am here to fight by your side as your partner.","TWN":"因為我之所以會在這裡，就是為了要和你這位合作夥伴一起作戰。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"그러니 제 화력이 필요할 때는 언제든 말씀하십시오.","JPN":"だから私の火力が必要な時はいつでもおっしゃってください。","ENG":"So speak freely whenever you require my firepower.","TWN":"所以需要我的火力支援時，請隨時開口。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저는 항상 당신 곁에, 출격 대기 중입니다.","JPN":"私は常にあなたのそばで出撃待機中です。","ENG":"I will always be on standby next to you.","TWN":"我會隨時在你身邊，等候出擊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};